const root=document.getElementById("root");const state={view:(location.hash||"#overview").slice(1),stats:{total:0,pending:0,failed:0,sent:0,activeStreams:0},notifications:[],templates:[],workflows:[],digests:[],message:"Dashboard ready.",expandedId:null};const views=["overview","notifications","templates","workflows","digest","queue"];const iso=v=>v?new Date(v).toISOString():"-";const dot=s=>{const c=s==="sent"||s==="completed"||s==="delivered"?"#22c55e":s==="failed"?"#ef4444":s==="pending"||s==="running"||s==="queued"?"#f59e0b":"#64748b";return`<span class="status-cell"><span class="status-dot" style="background:${c}"></span><span class="mono">${s}</span></span>`};async function api(url,init){const response=await fetch(url,init);const payload=await response.json();if(!response.ok)throw new Error(payload.error||"Request failed");return payload.data}async function load(){try{state.stats=await api("/health/stats");state.notifications=(await api("/notify")).items||[];state.templates=await api("/templates");state.workflows=await api("/workflows");const configs=await api("/digest/config");state.digests=await Promise.all(configs.map(async config=>({...config,pendingCount:(await api(`/digest/events/${config.key}/${config.user_id}`)).length})));state.message="Dashboard synced."}catch(error){state.message=error.message}render()}function panel(){if(state.view==="overview"){return `<section class="grid">${[["Total",state.stats.total],["Pending",state.stats.pending],["Failed",state.stats.failed],["Sent",state.stats.sent],["Active SSE",state.stats.activeStreams]].map(([l,v])=>`<article class="card"><p>${l}</p><strong>${v}</strong></article>`).join("")}</section>`}if(state.view==="notifications"){return `<table class="data-table"><thead><tr><th>ID</th><th>User</th><th>Type</th><th>Title</th><th>Status</th><th>Created</th><th>Read</th></tr></thead><tbody>${state.notifications.map(item=>`<tr data-row="${item.id}"><td class="mono">${item.id}</td><td class="mono">${item.user_id}</td><td>${item.type}</td><td>${item.title}</td><td>${dot(item.status)}</td><td class="mono">${iso(item.created_at)}</td><td class="mono">${iso(item.read_at)}</td></tr>${state.expandedId===item.id?`<tr class="expanded-row"><td colspan="7"><pre class="body-preview mono">${item.body}</pre></td></tr>`:""}`).join("")}</tbody></table>`}if(state.view==="templates"){return state.templates.length?state.templates.map(item=>`<article class="card"><strong>${item.slug}</strong><p class="placeholder mono">${item.channel}</p><pre class="body-preview mono">${item.body}</pre></article>`).join(""):'<p class="placeholder mono">no templates loaded</p>'}if(state.view==="workflows"){return state.workflows.length?state.workflows.map(item=>`<article class="card"><strong>${item.name}</strong><p class="placeholder mono">${item.slug}</p><pre class="body-preview mono">${JSON.stringify(item.steps,null,2)}</pre></article>`).join(""):'<p class="placeholder mono">no workflows loaded</p>'}if(state.view==="digest"){return `<table class="data-table"><thead><tr><th>Key</th><th>User</th><th>Window</th><th>Template</th><th>Pending</th><th></th></tr></thead><tbody>${state.digests.map(item=>`<tr><td class="mono">${item.key}</td><td class="mono">${item.user_id}</td><td class="mono">${item.window_ms}</td><td class="mono">${item.template_slug}</td><td class="mono">${item.pendingCount}</td><td><button data-flush="1" data-key="${item.key}" data-user="${item.user_id}">Flush</button></td></tr>`).join("")}</tbody></table>`}return '<p class="placeholder mono">Queue monitoring unavailable - configure REDIS_URL</p>'}function render(){root.innerHTML=`<div class="shell"><aside class="sidebar"><div class="brand"><div class="mono">[]</div><div><strong>NotiQ</strong><p>ops dashboard</p></div></div><nav class="nav">${views.map(view=>`<button class="nav-item ${state.view===view?"active":""}" data-view="${view}">${view}</button>`).join("")}</nav></aside><main class="main"><header class="topbar"><div><h1>${state.view}</h1><p>${state.message}</p></div><button id="refresh">Refresh</button></header>${panel()}</main></div>`;root.querySelectorAll("[data-view]").forEach(node=>node.addEventListener("click",()=>{state.view=node.getAttribute("data-view");location.hash=state.view;render()}));root.querySelector("#refresh")?.addEventListener("click",()=>void load());root.querySelectorAll("[data-row]").forEach(node=>node.addEventListener("click",()=>{const id=node.getAttribute("data-row");state.expandedId=state.expandedId===id?null:id;render()}));root.querySelectorAll("[data-flush]").forEach(node=>node.addEventListener("click",async()=>{await api("/digest/flush",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({key:node.getAttribute("data-key"),userId:node.getAttribute("data-user")})});await load()}))}window.addEventListener("hashchange",()=>{state.view=(location.hash||"#overview").slice(1);render()});void load();setInterval(()=>void load(),1e4);
